    private void ResetPaginationCts()
    {
        var oldCts = paginationContext.CancellationTokenSource;
        oldCts?.Cancel();
        paginationContext.CancellationTokenSource = new();
        oldCts?.Dispose();
    }

    private async void OnPageSizeChanged( int pageSize )
