    [Fact]
    public void MultiLevelGrouping_Should_GroupData_ByMultipleColumns()
    {
        // setup - use multiple employees to test multi-level grouping
        var employees = new List<Employee>()
        {
            new() { Name = "John", Department = "Engineering", City = "Zagreb" },
            new() { Name = "Ana", Department = "Engineering", City = "Split" },
            new() { Name = "Mark", Department = "Engineering", City = "Zagreb" },
            new() { Name = "Sarah", Department = "Sales", City = "Rijeka" },
            new() { Name = "Tom", Department = "Sales", City = "Rijeka" },
        };

        var comp = RenderComponent<BasicTestApp.Client.DataGridGroupingComponent>( parameters =>
        {
            parameters.Add( x => x.Data, employees );
        } );

        var dataGrid = comp.FindComponent<DataGrid<Employee>>();
        var columns = dataGrid.FindComponents<DataGridColumn<Employee>>();
        var departmentColumn = columns.Single( x => x.Instance.Field == nameof( Employee.Department ) );
        var cityColumn = columns.Single( x => x.Instance.Field == nameof( Employee.City ) );

        // test - add two levels of grouping (Department then City)
        dataGrid.Instance.AddGroupColumn( departmentColumn.Instance );
        dataGrid.Instance.AddGroupColumn( cityColumn.Instance );

        // validate - DisplayGroupedData should have nested groups
        var groupedData = dataGrid.Instance.DisplayGroupedData.ToList();

        // First level groups by Department
        groupedData.Should().HaveCount( 2 ); // Engineering, Sales

        var engineeringGroup = groupedData.Single( x => x.Key == "Engineering" );
        var salesGroup = groupedData.Single( x => x.Key == "Sales" );

        // Second level: Engineering -> nested groups by City (Zagreb, Split)
        engineeringGroup.NestedGroup.Should().NotBeNull();
        engineeringGroup.NestedGroup.Should().HaveCount( 2 );
        engineeringGroup.NestedGroup.Select( x => x.Key ).Should().Equal( "Split", "Zagreb" );

        // Second level: Sales -> nested groups by City (Rijeka)
        salesGroup.NestedGroup.Should().NotBeNull();
        salesGroup.NestedGroup.Should().HaveCount( 1 );
        salesGroup.NestedGroup.Single().Key.Should().Be( "Rijeka" );
    }
}

